+/**
+ * Analytics data models for the dashboard API.
+ *
+ * These types define the contract for analytics data flowing through
+ * the system. The AnalyticsService produces these types; route handlers
+ * return them as responses.
+ *
+ * Design notes:
+ * - TimeSeriesPoint is the atomic unit for all time-based charts
+ * - MetricSummary provides a snapshot with comparison to previous period
+ * - DashboardData is the composite response for the main dashboard view
+ * - Query interfaces define the input contract for each endpoint
+ */
+
+/**
+ * Granularity for time-series aggregation.
+ */
+export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';
+
+/**
+ * Supported metric types for the analytics API.
+ *
+ * - revenue: total order revenue over time
+ * - orders: order count over time
+ * - users: new user registrations over time
+ * - average-order-value: revenue / orders over time
+ */
+export type MetricType = 'revenue' | 'orders' | 'users' | 'average-order-value';
+
+/**
+ * A single data point in a time series.
+ */
+export interface TimeSeriesPoint {
+  /** ISO 8601 timestamp for the start of this bucket */
+  timestamp: string;
+  /** Numeric value for this bucket */
+  value: number;
+  /** Optional label (e.g., "Mon", "Week 12") */
+  label?: string;
+}
+
+/**
+ * Summary of a single metric with period-over-period comparison.
+ */
+export interface MetricSummary {
+  /** Which metric this summarizes */
+  metricType: MetricType;
+  /** Current period value */
+  currentValue: number;
+  /** Previous period value (same duration, immediately prior) */
+  previousValue: number;
+  /** Percentage change: ((current - previous) / previous) * 100 */
+  changePercent: number;
+  /** Direction of change */
+  trend: 'up' | 'down' | 'flat';
+  /** Human-readable formatted value (e.g., "$1,234.56", "128") */
+  formattedValue: string;
+}
+
+/**
+ * A breakdown row for categorical data (e.g., orders by status).
+ */
+export interface BreakdownItem {
+  /** Category label */
+  category: string;
+  /** Numeric value */
+  value: number;
+  /** Percentage of total */
+  percentage: number;
+}
+
+/**
+ * Top-level dashboard response containing all summary cards and charts.
+ */
+export interface DashboardData {
+  /** Summary cards for key metrics */
+  metrics: MetricSummary[];
+  /** Order count by status */
+  ordersByStatus: BreakdownItem[];
+  /** Recent orders time series (last 30 days, daily) */
+  recentOrdersTrend: TimeSeriesPoint[];
+  /** Revenue time series (last 30 days, daily) */
+  revenueTrend: TimeSeriesPoint[];
+  /** Timestamp when this data was generated */
+  generatedAt: string;
+}
+
+/**
+ * Query parameters for the dashboard endpoint.
+ */
+export interface DashboardQuery {
+  /** Start of the period (ISO 8601). Defaults to 30 days ago. */
+  startDate?: string;
+  /** End of the period (ISO 8601). Defaults to now. */
+  endDate?: string;
+}
+
+/**
+ * Query parameters for a single metric's time series.
+ */
+export interface MetricQuery {
+  /** Which metric to retrieve */
+  metricType: MetricType;
+  /** Start of the period (ISO 8601) */
+  startDate: string;
+  /** End of the period (ISO 8601) */
+  endDate: string;
+  /** Aggregation granularity. Defaults to 'day'. */
+  granularity?: TimeGranularity;
+}
+
+/**
+ * Response for a single metric time series endpoint.
+ */
+export interface MetricTimeSeriesResponse {
+  /** The requested metric */
+  metricType: MetricType;
+  /** Summary for the requested period */
+  summary: MetricSummary;
+  /** Time series data points */
+  series: TimeSeriesPoint[];
+  /** Query parameters that produced this result */
+  query: {
+    startDate: string;
+    endDate: string;
+    granularity: TimeGranularity;
+  };
+}
+
+/**
+ * Query parameters for the breakdown endpoint.
+ */
+export interface BreakdownQuery {
+  /** What dimension to break down by */
+  dimension: 'status' | 'user' | 'product';
+  /** Start of the period (ISO 8601) */
+  startDate?: string;
+  /** End of the period (ISO 8601) */
+  endDate?: string;
+  /** Maximum number of items to return. Defaults to 10. */
+  limit?: number;
+}
+
+/**
+ * Response for the breakdown endpoint.
+ */
+export interface BreakdownResponse {
+  dimension: string;
+  items: BreakdownItem[];
+  total: number;
+  query: {
+    startDate: string;
+    endDate: string;
+    limit: number;
+  };
+}

