+/**
+ * Analytics route handler definitions.
+ *
+ * Since this project is a framework-agnostic TypeScript library (no Express/Fastify),
+ * routes are defined as typed handler functions. Each handler takes a typed request
+ * and returns a typed response. A future integration layer can wire these to any
+ * HTTP framework.
+ *
+ * Route map:
+ *   GET /api/analytics/dashboard       -> handleGetDashboard
+ *   GET /api/analytics/metrics/:type   -> handleGetMetricTimeSeries
+ *   GET /api/analytics/breakdown       -> handleGetBreakdown
+ *
+ * Usage example (when wiring to Express):
+ *   app.get('/api/analytics/dashboard', (req, res) => {
+ *     const result = handleGetDashboard(analyticsService, req.query);
+ *     res.json(result);
+ *   });
+ */
+
+import type { AnalyticsService } from '../services/analytics.service.js';
+import type {
+  DashboardData,
+  DashboardQuery,
+  MetricType,
+  MetricQuery,
+  MetricTimeSeriesResponse,
+  BreakdownQuery,
+  BreakdownResponse,
+  TimeGranularity,
+} from '../models/analytics.js';
+
+/**
+ * Route definition describing an API endpoint.
+ */
+export interface RouteDefinition {
+  method: 'GET' | 'POST' | 'PUT' | 'DELETE';
+  path: string;
+  description: string;
+}
+
+/**
+ * All analytics routes for documentation and framework wiring.
+ */
+export const analyticsRoutes: RouteDefinition[] = [
+  {
+    method: 'GET',
+    path: '/api/analytics/dashboard',
+    description: 'Get the full dashboard view with summary metrics, trends, and breakdowns',
+  },
+  {
+    method: 'GET',
+    path: '/api/analytics/metrics/:type',
+    description: 'Get time series data for a single metric type',
+  },
+  {
+    method: 'GET',
+    path: '/api/analytics/breakdown',
+    description: 'Get categorical breakdown by dimension (status, user, product)',
+  },
+];
+
+const VALID_METRIC_TYPES: MetricType[] = ['revenue', 'orders', 'users', 'average-order-value'];
+const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];
+
+/**
+ * GET /api/analytics/dashboard
+ *
+ * Query params:
+ *   - startDate?: string (ISO 8601)
+ *   - endDate?: string (ISO 8601)
+ *
+ * Returns: DashboardData
+ */
+export function handleGetDashboard(
+  service: AnalyticsService,
+  queryParams: Record<string, string | undefined>,
+): DashboardData {
+  const query: DashboardQuery = {
+    startDate: queryParams['startDate'],
+    endDate: queryParams['endDate'],
+  };
+
+  return service.getDashboard(query);
+}
+
+/**
+ * GET /api/analytics/metrics/:type
+ *
+ * Path params:
+ *   - type: MetricType ('revenue' | 'orders' | 'users' | 'average-order-value')
+ *
+ * Query params:
+ *   - startDate: string (ISO 8601, required)
+ *   - endDate: string (ISO 8601, required)
+ *   - granularity?: TimeGranularity ('hour' | 'day' | 'week' | 'month')
+ *
+ * Returns: MetricTimeSeriesResponse
+ * Throws: Error if metricType is invalid or required params are missing
+ */
+export function handleGetMetricTimeSeries(
+  service: AnalyticsService,
+  pathParams: { type: string },
+  queryParams: Record<string, string | undefined>,
+): MetricTimeSeriesResponse {
+  const metricType = pathParams.type as MetricType;
+
+  if (!VALID_METRIC_TYPES.includes(metricType)) {
+    throw new Error(
+      `Invalid metric type: "${pathParams.type}". Valid types: ${VALID_METRIC_TYPES.join(', ')}`,
+    );
+  }
+
+  const startDate = queryParams['startDate'];
+  const endDate = queryParams['endDate'];
+
+  if (!startDate || !endDate) {
+    throw new Error('startDate and endDate query parameters are required');
+  }
+
+  const granularity = queryParams['granularity'] as TimeGranularity | undefined;
+  if (granularity && !VALID_GRANULARITIES.includes(granularity)) {
+    throw new Error(
+      `Invalid granularity: "${granularity}". Valid values: ${VALID_GRANULARITIES.join(', ')}`,
+    );
+  }
+
+  const query: MetricQuery = {
+    metricType,
+    startDate,
+    endDate,
+    granularity,
+  };
+
+  return service.getMetricTimeSeries(query);
+}
+
+/**
+ * GET /api/analytics/breakdown
+ *
+ * Query params:
+ *   - dimension: 'status' | 'user' | 'product' (required)
+ *   - startDate?: string (ISO 8601)
+ *   - endDate?: string (ISO 8601)
+ *   - limit?: string (number, defaults to 10)
+ *
+ * Returns: BreakdownResponse
+ * Throws: Error if dimension is invalid
+ */
+export function handleGetBreakdown(
+  service: AnalyticsService,
+  queryParams: Record<string, string | undefined>,
+): BreakdownResponse {
+  const dimension = queryParams['dimension'] as BreakdownQuery['dimension'] | undefined;
+  const validDimensions: BreakdownQuery['dimension'][] = ['status', 'user', 'product'];
+
+  if (!dimension || !validDimensions.includes(dimension)) {
+    throw new Error(
+      `Invalid or missing dimension. Valid values: ${validDimensions.join(', ')}`,
+    );
+  }
+
+  const limitStr = queryParams['limit'];
+  const limit = limitStr ? parseInt(limitStr, 10) : undefined;
+
+  if (limit !== undefined && (isNaN(limit) || limit < 1)) {
+    throw new Error('limit must be a positive integer');
+  }
+
+  const query: BreakdownQuery = {
+    dimension,
+    startDate: queryParams['startDate'],
+    endDate: queryParams['endDate'],
+    limit,
+  };
+
+  return service.getBreakdown(query);
+}

