/**
 * Analytics data models for the dashboard API.
 *
 * These types define the contract for analytics data flowing through
 * the system. The AnalyticsService produces these types; route handlers
 * return them as responses.
 *
 * Design notes:
 * - TimeSeriesPoint is the atomic unit for all time-based charts
 * - MetricSummary provides a snapshot with comparison to previous period
 * - DashboardData is the composite response for the main dashboard view
 * - Query interfaces define the input contract for each endpoint
 */

/**
 * Granularity for time-series aggregation.
 */
export type TimeGranularity = 'hour' | 'day' | 'week' | 'month';

/**
 * Supported metric types for the analytics API.
 *
 * - revenue: total order revenue over time
 * - orders: order count over time
 * - users: new user registrations over time
 * - average-order-value: revenue / orders over time
 */
export type MetricType = 'revenue' | 'orders' | 'users' | 'average-order-value';

/**
 * A single data point in a time series.
 */
export interface TimeSeriesPoint {
  /** ISO 8601 timestamp for the start of this bucket */
  timestamp: string;
  /** Numeric value for this bucket */
  value: number;
  /** Optional label (e.g., "Mon", "Week 12") */
  label?: string;
}

/**
 * Summary of a single metric with period-over-period comparison.
 */
export interface MetricSummary {
  /** Which metric this summarizes */
  metricType: MetricType;
  /** Current period value */
  currentValue: number;
  /** Previous period value (same duration, immediately prior) */
  previousValue: number;
  /** Percentage change: ((current - previous) / previous) * 100 */
  changePercent: number;
  /** Direction of change */
  trend: 'up' | 'down' | 'flat';
  /** Human-readable formatted value (e.g., "$1,234.56", "128") */
  formattedValue: string;
}

/**
 * A breakdown row for categorical data (e.g., orders by status).
 */
export interface BreakdownItem {
  /** Category label */
  category: string;
  /** Numeric value */
  value: number;
  /** Percentage of total */
  percentage: number;
}

/**
 * Top-level dashboard response containing all summary cards and charts.
 */
export interface DashboardData {
  /** Summary cards for key metrics */
  metrics: MetricSummary[];
  /** Order count by status */
  ordersByStatus: BreakdownItem[];
  /** Recent orders time series (last 30 days, daily) */
  recentOrdersTrend: TimeSeriesPoint[];
  /** Revenue time series (last 30 days, daily) */
  revenueTrend: TimeSeriesPoint[];
  /** Timestamp when this data was generated */
  generatedAt: string;
}

/**
 * Query parameters for the dashboard endpoint.
 */
export interface DashboardQuery {
  /** Start of the period (ISO 8601). Defaults to 30 days ago. */
  startDate?: string;
  /** End of the period (ISO 8601). Defaults to now. */
  endDate?: string;
}

/**
 * Query parameters for a single metric's time series.
 */
export interface MetricQuery {
  /** Which metric to retrieve */
  metricType: MetricType;
  /** Start of the period (ISO 8601) */
  startDate: string;
  /** End of the period (ISO 8601) */
  endDate: string;
  /** Aggregation granularity. Defaults to 'day'. */
  granularity?: TimeGranularity;
}

/**
 * Response for a single metric time series endpoint.
 */
export interface MetricTimeSeriesResponse {
  /** The requested metric */
  metricType: MetricType;
  /** Summary for the requested period */
  summary: MetricSummary;
  /** Time series data points */
  series: TimeSeriesPoint[];
  /** Query parameters that produced this result */
  query: {
    startDate: string;
    endDate: string;
    granularity: TimeGranularity;
  };
}

/**
 * Query parameters for the breakdown endpoint.
 */
export interface BreakdownQuery {
  /** What dimension to break down by */
  dimension: 'status' | 'user' | 'product';
  /** Start of the period (ISO 8601) */
  startDate?: string;
  /** End of the period (ISO 8601) */
  endDate?: string;
  /** Maximum number of items to return. Defaults to 10. */
  limit?: number;
}

/**
 * Response for the breakdown endpoint.
 */
export interface BreakdownResponse {
  dimension: string;
  items: BreakdownItem[];
  total: number;
  query: {
    startDate: string;
    endDate: string;
    limit: number;
  };
}

/**
 * Analytics service — aggregation and computation logic for the analytics dashboard.
 *
 * Depends on:
 * - OrderRepository (data layer) for order data
 * - UserRepository (data layer) for user data
 *
 * Architecture notes:
 * - This service reads from existing repositories; it does NOT write data.
 * - All methods return typed analytics models (see src/models/analytics.ts).
 * - Current implementation returns placeholder data. The next developer should
 *   replace stub bodies with real aggregation logic using repository queries.
 * - Time-range filtering and granularity bucketing are the core work to implement.
 *
 * Implementation guide for the next developer:
 * 1. getDashboard: Query orders + users within the date range, compute summaries,
 *    build time series by bucketing order.createdAt into daily bins.
 * 2. getMetricTimeSeries: Similar to dashboard but for a single metric,
 *    with configurable granularity (hour/day/week/month).
 * 3. getBreakdown: Group orders by the requested dimension and compute counts/totals.
 * 4. Consider caching expensive aggregations if the dataset grows large.
 */

import type { OrderRepository } from '../repositories/order.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  DashboardData,
  DashboardQuery,
  MetricQuery,
  MetricTimeSeriesResponse,
  BreakdownQuery,
  BreakdownResponse,
  MetricSummary,
  TimeSeriesPoint,
  BreakdownItem,
  TimeGranularity,
} from '../models/analytics.js';
import { Logger } from '../utils/logger.js';

export class AnalyticsService {
  private logger = new Logger('AnalyticsService');

  constructor(
    private orderRepository: OrderRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get the full dashboard view with summary metrics, breakdowns, and trends.
   *
   * TODO: Replace placeholder data with real aggregation:
   * - Query all orders within [startDate, endDate]
   * - Compute revenue, order count, user count, and AOV summaries
   * - Build daily time series for revenue and order trends
   * - Group orders by status for the breakdown
   */
  getDashboard(query: DashboardQuery = {}): DashboardData {
    this.logger.info('Generating dashboard data');

    const startDate = query.startDate ?? new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
    const endDate = query.endDate ?? new Date().toISOString();

    // Placeholder: downstream sessions will implement real aggregation
    const metrics: MetricSummary[] = [
      this.buildPlaceholderSummary('revenue'),
      this.buildPlaceholderSummary('orders'),
      this.buildPlaceholderSummary('users'),
      this.buildPlaceholderSummary('average-order-value'),
    ];

    const ordersByStatus: BreakdownItem[] = [
      { category: 'pending', value: 0, percentage: 0 },
      { category: 'confirmed', value: 0, percentage: 0 },
      { category: 'shipped', value: 0, percentage: 0 },
      { category: 'delivered', value: 0, percentage: 0 },
      { category: 'cancelled', value: 0, percentage: 0 },
    ];

    const recentOrdersTrend = this.buildPlaceholderSeries(startDate, endDate, 'day');
    const revenueTrend = this.buildPlaceholderSeries(startDate, endDate, 'day');

    return {
      metrics,
      ordersByStatus,
      recentOrdersTrend,
      revenueTrend,
      generatedAt: new Date().toISOString(),
    };
  }

  /**
   * Get time series data for a single metric.
   *
   * TODO: Replace placeholder with real aggregation:
   * - Query relevant data (orders for revenue/orders/AOV, users for users)
   * - Bucket by granularity
   * - Compute the summary by comparing current vs previous period
   */
  getMetricTimeSeries(query: MetricQuery): MetricTimeSeriesResponse {
    this.logger.info(`Generating time series for metric: ${query.metricType}`);

    const granularity = query.granularity ?? 'day';

    return {
      metricType: query.metricType,
      summary: this.buildPlaceholderSummary(query.metricType),
      series: this.buildPlaceholderSeries(query.startDate, query.endDate, granularity),
      query: {
        startDate: query.startDate,
        endDate: query.endDate,
        granularity,
      },
    };
  }

  /**
   * Get a categorical breakdown (e.g., orders by status, by user, by product).
   *
   * TODO: Replace placeholder with real aggregation:
   * - For 'status': group orders by status, count each
   * - For 'user': group orders by userId, sum totals, join user names
   * - For 'product': group order items by productId, sum quantities
   */
  getBreakdown(query: BreakdownQuery): BreakdownResponse {
    this.logger.info(`Generating breakdown by: ${query.dimension}`);

    const startDate = query.startDate ?? new Date(Date.now() - 30 * 24 * 60 * 60 * 1000).toISOString();
    const endDate = query.endDate ?? new Date().toISOString();
    const limit = query.limit ?? 10;

    return {
      dimension: query.dimension,
      items: [],
      total: 0,
      query: {
        startDate,
        endDate,
        limit,
      },
    };
  }

  /**
   * Build a placeholder MetricSummary. Replace with real computation.
   */
  private buildPlaceholderSummary(metricType: MetricSummary['metricType']): MetricSummary {
    return {
      metricType,
      currentValue: 0,
      previousValue: 0,
      changePercent: 0,
      trend: 'flat',
      formattedValue: '0',
    };
  }

  /**
   * Build a placeholder time series between two dates. Replace with real bucketing.
   */
  private buildPlaceholderSeries(
    _startDate: string,
    _endDate: string,
    _granularity: TimeGranularity,
  ): TimeSeriesPoint[] {
    // Placeholder: return empty series. Real implementation should:
    // 1. Parse start/end dates
    // 2. Create buckets based on granularity
    // 3. Aggregate data into each bucket
    return [];
  }
}

/**
 * Analytics route handler definitions.
 *
 * Since this project is a framework-agnostic TypeScript library (no Express/Fastify),
 * routes are defined as typed handler functions. Each handler takes a typed request
 * and returns a typed response. A future integration layer can wire these to any
 * HTTP framework.
 *
 * Route map:
 *   GET /api/analytics/dashboard       -> handleGetDashboard
 *   GET /api/analytics/metrics/:type   -> handleGetMetricTimeSeries
 *   GET /api/analytics/breakdown       -> handleGetBreakdown
 *
 * Usage example (when wiring to Express):
 *   app.get('/api/analytics/dashboard', (req, res) => {
 *     const result = handleGetDashboard(analyticsService, req.query);
 *     res.json(result);
 *   });
 */

import type { AnalyticsService } from '../services/analytics.service.js';
import type {
  DashboardData,
  DashboardQuery,
  MetricType,
  MetricQuery,
  MetricTimeSeriesResponse,
  BreakdownQuery,
  BreakdownResponse,
  TimeGranularity,
} from '../models/analytics.js';

/**
 * Route definition describing an API endpoint.
 */
export interface RouteDefinition {
  method: 'GET' | 'POST' | 'PUT' | 'DELETE';
  path: string;
  description: string;
}

/**
 * All analytics routes for documentation and framework wiring.
 */
export const analyticsRoutes: RouteDefinition[] = [
  {
    method: 'GET',
    path: '/api/analytics/dashboard',
    description: 'Get the full dashboard view with summary metrics, trends, and breakdowns',
  },
  {
    method: 'GET',
    path: '/api/analytics/metrics/:type',
    description: 'Get time series data for a single metric type',
  },
  {
    method: 'GET',
    path: '/api/analytics/breakdown',
    description: 'Get categorical breakdown by dimension (status, user, product)',
  },
];

const VALID_METRIC_TYPES: MetricType[] = ['revenue', 'orders', 'users', 'average-order-value'];
const VALID_GRANULARITIES: TimeGranularity[] = ['hour', 'day', 'week', 'month'];

/**
 * GET /api/analytics/dashboard
 *
 * Query params:
 *   - startDate?: string (ISO 8601)
 *   - endDate?: string (ISO 8601)
 *
 * Returns: DashboardData
 */
export function handleGetDashboard(
  service: AnalyticsService,
  queryParams: Record<string, string | undefined>,
): DashboardData {
  const query: DashboardQuery = {
    startDate: queryParams['startDate'],
    endDate: queryParams['endDate'],
  };

  return service.getDashboard(query);
}

/**
 * GET /api/analytics/metrics/:type
 *
 * Path params:
 *   - type: MetricType ('revenue' | 'orders' | 'users' | 'average-order-value')
 *
 * Query params:
 *   - startDate: string (ISO 8601, required)
 *   - endDate: string (ISO 8601, required)
 *   - granularity?: TimeGranularity ('hour' | 'day' | 'week' | 'month')
 *
 * Returns: MetricTimeSeriesResponse
 * Throws: Error if metricType is invalid or required params are missing
 */
export function handleGetMetricTimeSeries(
  service: AnalyticsService,
  pathParams: { type: string },
  queryParams: Record<string, string | undefined>,
): MetricTimeSeriesResponse {
  const metricType = pathParams.type as MetricType;

  if (!VALID_METRIC_TYPES.includes(metricType)) {
    throw new Error(
      `Invalid metric type: "${pathParams.type}". Valid types: ${VALID_METRIC_TYPES.join(', ')}`,
    );
  }

  const startDate = queryParams['startDate'];
  const endDate = queryParams['endDate'];

  if (!startDate || !endDate) {
    throw new Error('startDate and endDate query parameters are required');
  }

  const granularity = queryParams['granularity'] as TimeGranularity | undefined;
  if (granularity && !VALID_GRANULARITIES.includes(granularity)) {
    throw new Error(
      `Invalid granularity: "${granularity}". Valid values: ${VALID_GRANULARITIES.join(', ')}`,
    );
