 *
 * Returns: BreakdownResponse
 * Throws: Error if dimension is invalid
 */
export function handleGetBreakdown(
  service: AnalyticsService,
  queryParams: Record<string, string | undefined>,
): BreakdownResponse {
  const dimension = queryParams['dimension'] as BreakdownQuery['dimension'] | undefined;
  const validDimensions: BreakdownQuery['dimension'][] = ['status', 'user', 'product'];

  if (!dimension || !validDimensions.includes(dimension)) {
    throw new Error(
      `Invalid or missing dimension. Valid values: ${validDimensions.join(', ')}`,
    );
  }

  const limitStr = queryParams['limit'];
  const limit = limitStr ? parseInt(limitStr, 10) : undefined;

  if (limit !== undefined && (isNaN(limit) || limit < 1)) {
    throw new Error('limit must be a positive integer');
  }

  const query: BreakdownQuery = {
    dimension,
    startDate: queryParams['startDate'],
    endDate: queryParams['endDate'],
    limit,
  };

  return service.getBreakdown(query);
}

